import jwt
from jwt.exceptions import InvalidTokenError

def decode_and_verify_jwt(token, secret_key):
    try:
        # Decode the JWT without verifying the signature first
        decoded = jwt.decode(token, options={"verify_signature": False})
        print("Decoded Token (without verification):", decoded)
        
        # Verify the token with the secret key
        verified = jwt.decode(token, secret_key, algorithms=["HS256"])
        print("Verified Token:", verified)
        return verified
    except InvalidTokenError as e:
        print(f"Invalid token: {e}")
        return None

